function solve(nums) {
    const n = nums.length;
    if (n <= 1) {
        return new Array(n).fill(0);
    }

    const answer = new Array(n).fill(0);

    for (let i = 0; i < n; i++) {
        let score = 0;
        const parityI = nums[i] % 2; // 0 for even, 1 for odd

        // Iterate over j such that i < j < n
        for (let j = i + 1; j < n; j++) {
            const parityJ = nums[j] % 2;

